  ('heelevel3-29a002de-moex-00071', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列何種請求權，有消滅時效規定之適用？ 分割共有物之請求權  已登記不動產所有人之除去妨害請求權 夫妻間侵權行為而生之損害賠償請求權  夫妻關係而生之同居請求權 33120', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00072', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲有A跑車一部，A車因車禍致車體毀損。甲擅自取乙所有之油漆漆於A車，並向偷車集團購買 丙所有之同類新型引擎一個，安裝於A車。其後甲又將A車讓售於惡意之丁。下列敘述，何者正確？ 甲取得油漆之所有權，乙得依不當得利規定向甲請求償金 甲取得引擎之所有權，丙得依不當得利規定向甲請求償金 甲有權處分A車，丁不僅取得A車之所有權，亦取得油漆及引擎之所有權 乙得以其所有權受侵害為由，對惡意之丁主張侵權行為之損害賠償', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00073', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於錯誤意思表示之敘述，何者錯誤？ 甲欲與乙畫家締約，使乙畫家為甲畫肖像，但卻將丙畫家認為是乙畫家而與丙畫家締約，甲無 過失時，得撤銷其與丙間之契約 甲欲向丁購買A馬，卻未注意誤以為B馬為A馬而購買之，則甲得撤銷其與丁間之契約 甲內心欲以新臺幣（下同）300萬元出賣C車予戊，於書寫時寫成30萬元，甲無過失時，得撤 銷其與戊間之契約 甲以為前來應徵之庚，係曾在美國留學3年取得學位而與其訂立僱傭契約，甲無過失時，得撤 銷其與庚間之契約', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00074', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於附停止條件法律行為之敘述，何者錯誤？ 須以將來不確定之事實為法律行為附款 是法律行為之生效要件 條件成就時，縱無特約，皆回溯自約定條件時生效 條件成就前，尚未發生效力', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00075', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲竊取乙於丙銀行存款之存摺、印章及密碼後，於乙察覺遭竊前，甲持乙之印章、存摺及密碼至 丙銀行櫃臺，佯稱自己為乙，盜領乙之存款新臺幣十萬元。丙銀行於下列何種情形，得主張其已 對乙清償上述存款之債務？ 丙須不知甲非債權人而為給付 丙須無重大過失不知甲非債權人而為給付 丙須無具體輕過失不知甲非債權人而為給付 丙須無抽象輕過失不知甲非債權人而為給付', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00076', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '當事人無特約之情形下，下列何者無收取擔保物所生天然孳息之權利？ 典權人    扣押抵押物前之抵押權人 動產質權人    留置權人', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00077', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲給付遲延，其債權人乙一再請求甲提出給付，甲皆置之不理。下列敘述，何者正確？ 給付若定有期限，自期限屆滿時，債務人甲負遲延責任，乙得即時解除契約 乙解除契約後，雙方當事人僅得依民法第179條不當得利之規定，返還所受領之給付 乙解除契約後，乙對於甲仍得請求因遲延而生之損害賠償 乙應負受領遲延責任', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00078', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '乙對甲有新臺幣300萬元之債權，乙以該債權為標的，並為丙設定權利質權，且通知甲。下列敘 述，何者正確？ 該權利質權非不動產物權，其設定無須以書面為之 非經質權人丙之同意，出質人乙不得對債務人甲免除債務 債務人甲如向質權人丙為清償時，無須得出質人乙之同意 若債務人甲因其他法律關係取得對出質人乙之債權，甲均不得對乙主張抵銷 33120', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00079', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲與乙訂立買賣契約，將一幅名畫賣於乙，並以移轉所有權之意思交付於乙。嗣後，乙與丙訂立 贈與契約，將該幅名畫贈與丙，並以移轉所有權之意思交付於丙。甲主張意思表示錯誤，並於意 思表示後一年內向乙表示撤銷買賣契約，即僅撤銷債權契約，不撤銷物權契約。若甲無過失，而 乙與丙均為善意，下列敘述，何者正確? 乙對甲應負不當得利之返還義務  丙對甲不負不當得利之返還義務 乙與丙對甲應連帶負不當得利之返還義務  丙於乙免返還義務之限度內，負返還義務', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00080', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '限制行為能力人甲將同學乙之玩具贈與善意丙，並移轉玩具所有權於丙。該所有權移轉行為之效 力為何？ 有效  無效  效力未定  得撤銷', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
